```python
#!/usr/bin/env python3
import argparse
import subprocess
import sys

def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Dev environment manager CLI"
    )
    parser.add_argument(
        "-v", "--verbose",
        action="store_true",
        help="Enable verbose output"
    )
    return parser.parse_args()


def check_docker(verbose: bool) -> None:
    if verbose:
        print("[verbose] Checking if Docker is installed...")

    try:
        result = subprocess.run(
            ["docker", "--version"],
            capture_output=True, text=True, check=True
        )
        if verbose:
            print(f"[verbose] Docker version output: {result.stdout.strip()}")
        print("Docker is installed and accessible.")

        if verbose:
            print("[verbose] Checking if Docker daemon is running...")
        subprocess.run(
            ["docker", "info"],
            capture_output=True, text=True, check=True
        )
        print("Docker daemon is running.")

    except FileNotFoundError:
        print("ERROR: Docker is not installed or not in PATH.", file=sys.stderr)
        sys.exit(1)
    except subprocess.CalledProcessError:
        print("ERROR: Docker is installed but the daemon is not running.", file=sys.stderr)
        sys.exit(1)


def main() -> None:
    args = parse_args()
    check_docker(verbose=args.verbose)
    sys.exit(0)


if __name__ == "__main__":
    main()
```

`-v/--verbose` is wired up and passed through. Exit code `0` on success, `1` on any error — consistent with Unix convention.

