import subprocess
import sys


def cmd_status(verbose: bool) -> int:
    if verbose:
        print("[verbose] Running: docker compose ps")

    try:
        result = subprocess.run(
            ["docker", "compose", "ps"],
            capture_output=True,
            text=True
        )

        if result.returncode != 0:
            print("ERROR: Failed to get container status.", file=sys.stderr)
            if verbose:
                print(f"[verbose] stderr: {result.stderr.strip()}", file=sys.stderr)
            return 1

        if verbose:
            print("[verbose] docker compose ps output:")

        output = result.stdout.strip()
        if not output:
            print("No services are currently running.")
        else:
            print(output)

        return 0

    except FileNotFoundError:
        print("ERROR: 'docker' command not found.", file=sys.stderr)
        return 1
    except Exception as e:
        print(f"ERROR: Unexpected error in status: {e}", file=sys.stderr)
        return 1
```

Always captures output so we can inspect it before printing — empty output means no services running. `-v/--verbose` adds context about what command is being run. Returns `0` on success, `1` on any error. Add `"status"` to the subparser and dispatch table in `main()`.

