# devtool/commands/healthcheck.py
import sys
from typing import List, Tuple, Optional


def parse_host_port(raw: str) -> Optional[Tuple[str, int]]:
    """
    Parses 'host:port' strings. Returns None and prints an error if invalid.
    """
    try:
        if ":" not in raw:
            raise ValueError("Missing ':' separator")
        host, port_str = raw.rsplit(":", 1)
        port = int(port_str)
        if not (1 <= port <= 65535):
            raise ValueError(f"Port must be between 1 and 65535, got {port}")
        if not host:
            raise ValueError("Host cannot be empty")
        return host, port
    except ValueError as e:
        print(
            f"ERROR: Invalid port argument '{raw}': {e}. "
            f"Expected format: host:port (e.g. localhost:5432)",
            file=sys.stderr
        )
        return None


def cmd_healthcheck(raw_ports: List[str], verbose: bool) -> int:
    parsed = []
    for raw in raw_ports:
        result = parse_host_port(raw)
        if result is None:
            return 1  # bad argument = exit 1 immediately
        parsed.append(result)

    if verbose:
        print(f"[verbose] Checking {len(parsed)} port(s)...")

    all_ok = True
    for host, port in parsed:
        if verbose:
            print(f"[verbose] Checking {host}:{port}...")
        if check_port(host, port):
            print(f"OK: {host}:{port} is accepting connections.")
        else:
            print(f"FAIL: {host}:{port} is not reachable.", file=sys.stderr)
            all_ok = False

    return 0 if all_ok else 1
```

`parse_host_port` returns `None` on bad input and prints a descriptive error to `stderr`. The caller exits immediately with `1` — bad argument = error exit code. No silent failures. `-v/--verbose` shows how many ports are being checked. Valid input still returns `0` on success, `1` if a port is unreachable.

