# devtool/commands/clean.py
import subprocess
import sys
from typing import List, Tuple


def run_docker_prune(cmd: List[str], label: str, verbose: bool) -> Tuple[bool, str]:
    """
    Runs a docker prune command.
    Returns (success: bool, output: str).
    """
    if verbose:
        print(f"[verbose] Running: {' '.join(cmd)}")
    try:
        result = subprocess.run(cmd, capture_output=True, text=True)
        if result.returncode != 0:
            return False, result.stderr.strip()
        return True, result.stdout.strip()
    except FileNotFoundError:
        return False, "'docker' command not found"
    except Exception as e:
        return False, str(e)


def cmd_clean(
    containers: bool,
    images: bool,
    volumes: bool,
    verbose: bool,
) -> int:
    if not any([containers, images, volumes]):
        # Default: clean everything
        containers = images = volumes = True

    all_ok = True

    if containers:
        ok, out = run_docker_prune(
            ["docker", "container", "prune", "-f"],
            "containers", verbose
        )
        if ok:
            print(f"OK: Stopped containers removed. {out}")
        else:
            print(f"ERROR: Failed to prune containers: {out}", file=sys.stderr)
            all_ok = False

    if images:
        ok, out = run_docker_prune(
            ["docker", "image", "prune", "-f"],
            "images", verbose
        )
        if ok:
            print(f"OK: Dangling images removed. {out}")
        else:
            print(f"ERROR: Failed to prune images: {out}", file=sys.stderr)
            all_ok = False

    if volumes:
        ok, out = run_docker_prune(
            ["docker", "volume", "prune", "-f"],
            "volumes", verbose
        )
        if ok:
            print(f"OK: Unused volumes removed. {out}")
        else:
            print(f"ERROR: Failed to prune volumes: {out}", file=sys.stderr)
            all_ok = False

    return 0 if all_ok else 1
