# devtool/commands/clean.py
import subprocess
import sys
from typing import List, Tuple


def list_prunable(resource: str, verbose: bool) -> Tuple[bool, List[str]]:
    """
    Lists resources that would be pruned, without removing them.
    resource: 'containers', 'images', or 'volumes'
    """
    cmd_map = {
        "containers": ["docker", "ps", "-a", "--filter", "status=exited", "--format", "{{.Names}}"],
        "images":     ["docker", "images", "-f", "dangling=true", "--format", "{{.Repository}}:{{.Tag}}"],
        "volumes":    ["docker", "volume", "ls", "-f", "dangling=true", "--format", "{{.Name}}"],
    }
    cmd = cmd_map[resource]
    if verbose:
        print(f"[verbose] Running: {' '.join(cmd)}")
    try:
        result = subprocess.run(cmd, capture_output=True, text=True)
        if result.returncode != 0:
            return False, []
        items = [line for line in result.stdout.strip().splitlines() if line]
        return True, items
    except Exception:
        return False, []


def cmd_clean(
    containers: bool,
    images: bool,
    volumes: bool,
    dry_run: bool,
    verbose: bool,
) -> int:
    if not any([containers, images, volumes]):
        containers = images = volumes = True

    if dry_run:
        print("DRY RUN — no changes will be made.")

    all_ok = True
    targets = [
        ("containers", containers),
        ("images",     images),
        ("volumes",    volumes),
    ]

    for resource, should_clean in targets:
        if not should_clean:
            continue
        if dry_run:
            ok, items = list_prunable(resource, verbose)
            if not ok:
                print(f"ERROR: Could not list {resource}.", file=sys.stderr)
                all_ok = False
                continue
            if items:
                print(f"Would remove {len(items)} {resource}:")
                for item in items:
                    print(f"  - {item}")
            else:
                print(f"No {resource} to remove.")
        else:
            cmd = ["docker", resource.rstrip('s'), "prune", "-f"] if resource != "images" \
                  else ["docker", "image", "prune", "-f"]
            if verbose:
                print(f"[verbose] Running: {' '.join(cmd)}")
            try:
                result = subprocess.run(cmd, capture_output=True, text=True)
                if result.returncode != 0:
                    print(f"ERROR: Failed to prune {resource}.", file=sys.stderr)
                    all_ok = False
                else:
                    print(f"OK: {resource.capitalize()} pruned.")
            except Exception as e:
                print(f"ERROR: {e}", file=sys.stderr)
                all_ok = False

    return 0 if all_ok else 1
```

Add `--dry-run` to the subparser:
```python
clean_p.add_argument("--dry-run", action="store_true", help="Show what would be removed without making changes")
clean_p.add_argument("-v", "--verbose", action="store_true", help="Enable verbose output")
```

`--dry-run` lists what would be pruned without executing any destructive commands. Returns `0` on success, `1` if listing fails. Exit codes and `-v/--verbose` behave identically in dry-run and live modes.
